import{_ as a,c as n,o as i,ae as t}from"./chunks/framework.D4x4JNJ3.js";const g=JSON.parse('{"title":"Changelog v2025.2.x","description":"","frontmatter":{"title":"Changelog v2025.2.x"},"headers":[],"relativePath":"en/changelog/v2025.2.x.md","filePath":"en/changelog/v2025.2.x.md","lastUpdated":1772097359000}'),o={name:"en/changelog/v2025.2.x.md"};function l(s,e,r,d,m,c){return i(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="mogan-stem-v2025-2-x-changelog" tabindex="-1">Mogan STEM v2025.2.x Changelog <a class="header-anchor" href="#mogan-stem-v2025-2-x-changelog" aria-label="Permalink to “Mogan STEM v2025.2.x Changelog”">​</a></h1><blockquote><p>Note: Liii STEM is the commercial edition of Mogan STEM. It provides value-added features on top of the open-source version, such as account login and AI. For more details, see Liii STEM: <a href="https://liiistem.com/docs/changelog-v2025.2.x.html" target="_blank" rel="">v2025.2.x</a></p></blockquote><h2 id="⭐️-new-features-highlights" tabindex="-1">⭐️ New Features &amp; Highlights <a class="header-anchor" href="#⭐️-new-features-highlights" aria-label="Permalink to “⭐️ New Features &amp; Highlights”">​</a></h2><ol><li><strong>Python plugin rendering upgrade</strong>: Render Matplotlib plots, SymPy formulas, and Pandas tables as editable content, with support for foldable executable code blocks.</li><li><strong>Structured find/replace</strong>: A more modern search/replace experience for structured content, including formulas, symbols, and matrices.</li><li><strong>Night mode and comments</strong>: Night mode for both UI and documents; comments that can be inserted and folded/unfolded, supporting formulas and more.</li><li><strong>Performance and stability</strong>: Major math-mode performance improvements; typesetting engine optimization (Chinese punctuation compression); fixed Windows menu bar disappearing at 125% scaling.</li><li><strong>Pinned tabs</strong>: Support for pinning tabs (Chrome-like experience).</li><li><strong>Vector images and formats</strong>: Native PDF vector image support; added WebP image support.</li><li><strong>Plugin ecosystem and environments</strong>: Better support for plugins like Python/Maxima/Gnuplot, plus conda environment support.</li><li><strong>Document and input enhancements</strong>: More flexible page numbering; more symbols and Tab Cycling inputs (such as <code>\\textendash</code>/<code>\\textemdash</code>, LEGO symbols); underline/strikethrough and other small UX improvements. (Liii STEM additionally provides value-added features such as AI and OCR.)</li></ol><h2 id="🌟-summary" tabindex="-1">🌟 Summary <a class="header-anchor" href="#🌟-summary" aria-label="Permalink to “🌟 Summary”">​</a></h2><p>The v2025.2.x line focuses on a big upgrade to “runnable plugins + editing/typesetting experience + format support”: a smoother Python rendering pipeline where plots/formulas/tables become directly editable, plus native PDF vector images and WebP support. The line also iterates on structured find/replace, night mode, comments, Chinese typesetting, and cross-platform stability. Liii STEM builds on top of this with value-added features such as login, AI, and OCR.</p><h2 id="🔧-release-notes" tabindex="-1">🔧 Release Notes <a class="header-anchor" href="#🔧-release-notes" aria-label="Permalink to “🔧 Release Notes”">​</a></h2><h3 id="mogan-stem-v2025-2-3-2026-01-06" tabindex="-1">Mogan STEM v2025.2.3 (2026/01/06) <a class="header-anchor" href="#mogan-stem-v2025-2-3-2026-01-06" aria-label="Permalink to “Mogan STEM v2025.2.3 (2026/01/06)”">​</a></h3><ol><li>More modern structured find/replace, including formulas, symbols, and matrices.</li><li>New night mode for both UI and documents.</li><li>New comments: insert comments and fold/unfold them; comment content supports formulas, etc.</li><li>Typesetting engine optimization: Chinese punctuation compression.</li><li>Tab Cycling improvements: new inputs for <code>mathcal</code>/<code>mathbf</code>/<code>mathfrak</code>; <code>n</code> gains a <code>\\nabla</code> variant.</li><li>Image floating menu: quick layout adjustments; (Liii STEM) OCR recognition.</li><li><code>nbsp</code> display tweaks: non-breaking spaces use an invisible color by default and can be adjusted.</li></ol><h3 id="mogan-stem-v2025-2-2-2025-12-10" tabindex="-1">Mogan STEM v2025.2.2 (2025/12/10) <a class="header-anchor" href="#mogan-stem-v2025-2-2-2025-12-10" aria-label="Permalink to “Mogan STEM v2025.2.2 (2025/12/10)”">​</a></h3><ol><li>(Liii STEM) Integrated a high-speed DeepSeek V3.2 (AI) and enabled direct interaction with formulas.</li><li>Significantly improved math-mode editing performance and fixed Tab Cycling stutters.</li><li>Fixed Windows menu bar disappearing at 125% scaling.</li><li>Table environments can be rotated to any angle.</li><li>Updated the background color of foldable code blocks.</li><li>Added underline and strikethrough (can be used with the Comment plugin).</li></ol><h3 id="mogan-stem-v2025-2-1-2025-12-03" tabindex="-1">Mogan STEM v2025.2.1 (2025/12/03) <a class="header-anchor" href="#mogan-stem-v2025-2-1-2025-12-03" aria-label="Permalink to “Mogan STEM v2025.2.1 (2025/12/03)”">​</a></h3><ol><li>Python plugin rendering upgrade: Matplotlib plots, SymPy formulas, and Pandas tables rendered as editable content; foldable executable code blocks with source preserved.</li><li>Plugins and environments: conda support; improved Maxima and Gnuplot plugin rendering and demos.</li><li>Formats and images: native PDF vector images; added WebP support.</li><li>Tabs: pinned tabs.</li><li>Editor UX: cursor color/blinking and selection color improvements; more flexible page numbering.</li><li>Other updates: more symbols and Tab Cycling inputs (such as <code>\\textendash</code>/<code>\\textemdash</code>, LEGO symbols); Appendix option and shortcuts in the mode toolbar.</li><li>Commercial edition: Liii STEM v2025.2.1 released in parallel (login support, public beta).</li></ol><h2 id="👏-join-us" tabindex="-1">👏 Join Us <a class="header-anchor" href="#👏-join-us" aria-label="Permalink to “👏 Join Us”">​</a></h2><ul><li>Mogan STEM Official Website: <a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li><li>Mogan Community QQ Group: <a href="https://qun.qq.com/universal-share/share?ac=1&amp;authKey=NoxIHFT4nzWfHJnqGNQygmXt%2FhpydluCE%2FcF1qMzu1BHpNNjv7ZGZxWwS0fGx32Y&amp;busi_data=eyJncm91cENvZGUiOiI5MzQ0NTY5NzEiLCJ0b2tlbiI6InpOMGxCaHIvdEtyM1V1d0VGYlpTQThZZ2NDODQxUjU1dWdBZEF5cG9MUHptN3R6Q1NXenNaWVluOVpjOTd3VHAiLCJ1aW4iOiI3ODUyNTEzMjIifQ%3D%3D&amp;data=n9XWNwOuQOWPbezHFAHZS24nvSli9BNzrLjrfFr_JWfStSboc6G5DZwBXWzZDqXc5A29OptCvKgtVjZ1Gwmu1A&amp;svctype=4&amp;tempid=h5_group_info" target="_blank" rel="">934456971</a></li><li>Discord Group: <a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li></ul>',15)])])}const h=a(o,[["render",l]]);export{g as __pageData,h as default};
